    // 每 1000 现实毫秒 = 1 游戏分钟
    this.msPerGameMinute = 1000;

    // 是否暂停
    this.isTimePaused = false;

    // 上一次更新的现实时间戳
    this._lastRealTime = null;

    // 新一天回调列表
    this._onNewDayCallbacks = [];
  }

  // ========== 核心更新 ==========

  // 每帧调用，delta 为现实毫秒
